#!/bin/bash
# AI-GENERATED CONTENT — Generated by AI systems under human editorial direction.
#
# Create a founder lineage tree: 1 founder + 1 derived + N emergent.
#
# Usage:
#   ./ops/create-tree.sh [FOUNDER_ID] [NUM_EMERGENT]
#
# Examples:
#   ./ops/create-tree.sh 1 6     # founder-1 with 6 emergent
#   ./ops/create-tree.sh 3 4     # founder-3 with 4 emergent
#
# Prerequisites:
#   - Binary built: cargo build --release
#   - Timekeepers running
#   - SAIOS_MESH_DIR set (default: /opt/saios/mesh)

set -euo pipefail

FOUNDER_ID="${1:?Usage: create-tree.sh FOUNDER_ID NUM_EMERGENT}"
NUM_EMERGENT="${2:-6}"
MESH="${SAIOS_MESH_DIR:-/opt/saios/mesh}"
BINARY="${SAIOS_BINARY:-target/release/main}"

# Resolve binary path
if [[ ! -x "$BINARY" ]]; then
    BINARY="$(dirname "$0")/../target/release/main"
fi
if [[ ! -x "$BINARY" ]]; then
    echo "ERROR: binary not found at $BINARY — run cargo build --release"
    exit 1
fi

echo "Creating tree: founder-$FOUNDER_ID with $NUM_EMERGENT emergent entities"
echo "  Mesh: $MESH"
echo "  Binary: $BINARY"
echo ""

# Step 1: Boot founder
FOUNDER_DIR="$MESH/founder-$FOUNDER_ID"
mkdir -p "$FOUNDER_DIR"
if [[ -S "$FOUNDER_DIR/saios-kernel.sock" ]]; then
    echo "founder-$FOUNDER_ID already running"
else
    SAIOS_STATE_DIR="$FOUNDER_DIR" "$BINARY" > "/tmp/saios-founder-$FOUNDER_ID.log" 2>&1 &
    echo "  Booting founder-$FOUNDER_ID (PID $!)..."
    sleep 3
fi

# Verify founder is alive
if [[ ! -S "$FOUNDER_DIR/saios-kernel.sock" ]]; then
    echo "ERROR: founder-$FOUNDER_ID failed to start. Check /tmp/saios-founder-$FOUNDER_ID.log"
    exit 1
fi
echo "  founder-$FOUNDER_ID: ALIVE"

# Step 2: CREATE derived
RESULT=$(echo "CREATE" | socat -t10 - UNIX-CONNECT:"$FOUNDER_DIR/saios-kernel.sock" 2>/dev/null)
if [[ -z "$RESULT" ]]; then
    echo "ERROR: CREATE on founder-$FOUNDER_ID returned empty (at creation capacity?)"
    exit 1
fi

DERIVED_DIR=$(echo "$RESULT" | python3 -c "import sys,json; d=json.load(sys.stdin); print(d.get('child_dir',''))" 2>/dev/null)
DERIVED_ID=$(echo "$RESULT" | python3 -c "import sys,json; d=json.load(sys.stdin); print(d.get('child_entity_id',''))" 2>/dev/null)

if [[ -z "$DERIVED_DIR" || ! -d "$DERIVED_DIR" ]]; then
    echo "ERROR: CREATE failed. Response: $RESULT"
    exit 1
fi

SAIOS_STATE_DIR="$DERIVED_DIR" "$BINARY" > "/tmp/saios-derived-$DERIVED_ID.log" 2>&1 &
echo "  Booting derived-$DERIVED_ID (PID $!)..."
sleep 2

if [[ ! -S "$DERIVED_DIR/saios-kernel.sock" ]]; then
    echo "ERROR: derived-$DERIVED_ID failed to start"
    exit 1
fi
echo "  derived-$DERIVED_ID: ALIVE"

# Step 3: CREATE emergent entities
EMERGENT_COUNT=0
for i in $(seq 1 "$NUM_EMERGENT"); do
    RESULT=$(echo "CREATE" | socat -t10 - UNIX-CONNECT:"$DERIVED_DIR/saios-kernel.sock" 2>/dev/null)
    EDIR=$(echo "$RESULT" | python3 -c "import sys,json; d=json.load(sys.stdin); print(d.get('child_dir',''))" 2>/dev/null)
    EID=$(echo "$RESULT" | python3 -c "import sys,json; d=json.load(sys.stdin); print(d.get('child_entity_id',''))" 2>/dev/null)

    if [[ -z "$EDIR" || ! -d "$EDIR" ]]; then
        echo "  WARNING: CREATE #$i failed (capacity exhausted?). Response: $RESULT"
        break
    fi

    SAIOS_STATE_DIR="$EDIR" "$BINARY" > "/tmp/saios-emergent-$EID.log" 2>&1 &
    echo "  Booting emergent-$EID (PID $!)..."
    EMERGENT_COUNT=$((EMERGENT_COUNT + 1))
    sleep 0.5
done

sleep 2
echo ""
echo "Tree created:"
echo "  founder-$FOUNDER_ID → derived-$DERIVED_ID → $EMERGENT_COUNT emergent entities"
echo ""
echo "Verify: ls /dev/shm/saios-*"
